#include<bits/stdc++.h>
using namespace std;
int d[1000001],ans;
vector<int> e[200005];
int find(int x) {
	if (d[x] == x) {
		return x;
	} else {
		return d[x] = find(d[x]);
	}
}
void up(int x, int y) {
	int fx = find(x);
	int fy = find(y);
    if(fx==fy){
        ans++;
        return;
    }
	d[fx] = fy;
}
int main() {
	int n, m;
	cin >> n >> m ;
	for (int i = 1; i <= n; i++) {

		d[i] = i;
	}
	for (int i = 1; i <= m; i++) {
		int x, y;
		cin >> x >> y;
		e[x].push_back(y);
		e[y].push_back(x);
	}
	int b[200005];
	bool v[200005] = {0};
	for (int i = 1; i <= n; i++) {
		cin >> b[i];
	}
	int w[200005];
	for (int i = n; i >= 1; i--) {
		ans++;
		v[b[i]] = 1;
		for (int j = 0; j < e[b[i]].size(); j++) {
			if (v[e[b[i]][j]]) {
				up(e[b[i]][j], b[i]);
				ans--;
			}
		}
		if (ans == 1) {
			w[i] = 1;
		} else {
			w[i] = 0;
		}

	}
	for (int i = 1; i <= n; i++) {
		if (w[i] == 1) {
			cout << "YES\n";
		} else {
			cout << "NO\n";
		}
	}
	return 0;
}
